def trimmed_mean(nums):
    if not nums:
        return None
    sorted_nums = sorted(nums)
    n = len(sorted_nums)
    median_index = (n - 1) // 2
    min_index, max_index = median_index, median_index + 1
    if len(nums) % 2 == 0:
        min_index -= 1
        max_index += 1
    return sum(sorted_nums[min_index+1:max_index]) / (n - 2)
